 1	import React, { FC, useCallback } from 'react';
 2	
 3	import { TemplateModel, V1Template } from '@kubevirt-ui/kubevirt-api/console';
 4	import SidebarEditor from '@kubevirt-utils/components/SidebarEditor/SidebarEditor';
 5	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 6	import { k8sUpdate } from '@openshift-console/dynamic-plugin-sdk';
 7	import { Grid, GridItem, PageSection, PageSectionVariants, Title } from '@patternfly/react-core';
 8	
 9	import TemplateDetailsLeftGrid from './components/TemplateDetailsLeftGrid';
10	import TemplateDetailsRightGrid from './components/TemplateDetailsRightGrid';
11	
12	import './TemplateDetailsPage.scss';
13	
14	export type TemplateDetailsGridProps = {
15	  editable?: boolean;
16	  template: V1Template;
17	};
18	
19	export type LabelsAnnotationsType = { [key: string]: string };
20	
21	type TemplateDetailsPageProps = {
22	  obj?: V1Template;
23	};
24	
25	const TemplateDetailsPage: FC<TemplateDetailsPageProps> = ({ obj: template }) => {
26	  const { t } = useKubevirtTranslation();
27	
28	  const onSubmitTemplate = useCallback(
29	    (updatedTemplate: V1Template) =>
30	      k8sUpdate({
31	        data: updatedTemplate,
32	        model: TemplateModel,
33	        name: updatedTemplate?.metadata?.name,
34	        ns: updatedTemplate?.metadata?.namespace,
35	      }),
36	    [],
37	  );
38	
39	  return (
40	    <PageSection variant={PageSectionVariants.light}>
41	      <SidebarEditor<V1Template> onResourceUpdate={onSubmitTemplate} resource={template}>
42	        {(resource) => (
43	          <>
44	            <Title headingLevel="h2">{t('Template details')}</Title>
45	            <Grid className="margin-top">
46	              <GridItem span={5}>
47	                <TemplateDetailsLeftGrid template={resource} />
48	              </GridItem>
49	              <GridItem lg={1}></GridItem>
50	              <GridItem span={5}>
51	                <TemplateDetailsRightGrid template={resource} />
52	              </GridItem>
53	            </Grid>
54	          </>
55	        )}
56	      </SidebarEditor>
57	    </PageSection>
58	  );
59	};
60	
61	export default TemplateDetailsPage;

